export function scale(image: string[], scaleFactor: number): string[] {
  if (image.length === 0) {
    return [];
  }

  const isSingleRow = image.length === 1;
  const isSingleColumn = image.every((line) => line.length === 1);

  if (isSingleRow && isSingleColumn) {
    // Single pixel: scale both horizontally and vertically
    return scaleVerticalLines(scaleHorizontalLines(image, scaleFactor), scaleFactor);
  }

  if (isSingleRow) {
    // Single row: scale vertically only
    return scaleVerticalLines(image, scaleFactor);
  }

  if (isSingleColumn) {
    // Single column: scale horizontally only
    return scaleHorizontalLines(image, scaleFactor);
  }

  // Multi-row, multi-column grid: scale both horizontally and vertically
  const horizontallyScaled = scaleHorizontalLines(image, scaleFactor);
  return scaleVerticalLines(horizontallyScaled, scaleFactor);
}

